            }
        }
    }

    #[inline]
    fn try_convert_to_bytes(&self, slice: &mut [u8], cursor: &mut usize) -> Result<()> {
        match self.as_ref() {
            Some(s) => {
                try_push(slice, cursor, 1)?;
                s.try_convert_to_bytes(slice, cursor)?;
