                push(slice, cursor, 1);
                s.convert_to_bytes(slice, cursor);
            }
            None => {
                push(slice, cursor, 0);
            }
        }
    }
}

impl<T: Rapira, E: Rapira> Rapira for Result<T, E> {
    const STATIC_SIZE: Option<usize> = enum_size([T::STATIC_SIZE, E::STATIC_SIZE]);
    const MIN_SIZE: usize = enum_min_size(&[T::MIN_SIZE, E::MIN_SIZE]);

    #[inline]
    fn size(&self) -> usize {
        match self {
            Ok(t) => 1 + t.size(),
            Err(e) => 1 + e.size(),
        }
    }

    #[inline]
