    where
        Self: Sized,
    {
        let discriminant = byte_rapira::from_slice(slice)?;
        match discriminant {
            0 => Ok(Ok(T::from_slice(slice)?)),
            1 => Ok(Err(E::from_slice(slice)?)),
            _ => Err(RapiraError::EnumVariant),
        }
    }

    #[inline]
