where
    T: Rapira + Sized,
{
    const STATIC_SIZE: Option<usize> = static_size([T::STATIC_SIZE; CAP]);
    const MIN_SIZE: usize = CAP * T::MIN_SIZE;

    #[inline]
    fn size(&self) -> usize {
