    fn from_slice(slice: &mut &[u8]) -> Result<Self>
    where
        Self: Sized,
    {
        let mut arr: [MaybeUninit<T>; CAP] = unsafe { MaybeUninit::uninit().assume_init() };

        for i in 0..CAP {
            match T::from_slice(slice) {
                Ok(val) => {
                    arr.get_mut(i).ok_or(RapiraError::SliceLen)?.write(val);
