                        let s = arr.get_mut(0..i).ok_or(RapiraError::SliceLen)?;

                        for item in s {
                            unsafe {
                                item.assume_init_drop();
                            }
                        }
                    }
                    return Err(err);
                }
            }
        }

        let arr: [T; CAP] = arr.map(|i| unsafe { i.assume_init() });

        Ok(arr)
    }

