                    }
                    Err(err) => {
                        if i != 0 {
                            for item in arr.get_unchecked_mut(0..i) {
                                item.assume_init_drop();
                            }
                        }
                        return Err(err);
                    }
                }
            }

            let arr: [T; CAP] = arr.map(|i| i.assume_init());
            Ok(arr)
        }
    }

