  9→use crate::{
 10→    field_attrs::{extract_idx_attr, extract_with_attr, skip_attr},
 11→    shared::build_ident,
 12→};
 13→
 14→pub fn struct_serializer(
 15→    data_struct: &DataStruct,
 16→    name: &Ident,
 17→    generics: Generics,
 18→    is_debug: bool,
 19→) -> proc_macro::TokenStream {
 20→    let fields = &data_struct.fields;
 21→    match fields {
 22→        Fields::Named(fields) => {
 23→            let named = &fields.named;
 24→            let named_len = named.len();
 25→
 26→            let mut fields_insert: Vec<(Field, u32, Option<ExprPath>)> =
 27→                Vec::with_capacity(named_len);
 28→            let mut seq = 0u32;
 29→
 30→            let iter = named.iter().filter(|field| !skip_attr(&field.attrs));
 31→
 32→            for field in iter {
 33→                let field_idx = extract_idx_attr(&field.attrs).unwrap_or_else(|| {
 34→                    let current_seq = seq;
 35→                    seq += 1;
 36→                    current_seq
 37→                });
 38→
 39→                let field_with_attr = extract_with_attr(&field.attrs);
 40→
 41→                fields_insert.push((field.clone(), field_idx, field_with_attr));
 42→            }
 43→
 44→            fields_insert.sort_by(|(_, idx_a, _), (_, idx_b, _)| idx_a.cmp(idx_b));
 45→
 46→            let mut field_names: Vec<TokenStream> = Vec::with_capacity(named_len);
 47→            let mut from_slice: Vec<TokenStream> = Vec::with_capacity(named_len);
 48→            let mut debug_from_slice: Vec<TokenStream> = Vec::with_capacity(named_len);
 49→            let mut check_bytes: Vec<TokenStream> = Vec::with_capacity(named_len);
 50→            let mut from_slice_unchecked: Vec<TokenStream> = Vec::with_capacity(named_len);
 51→            let mut from_slice_unsafe: Vec<TokenStream> = Vec::with_capacity(named_len);
 52→            let mut try_convert_to_bytes: Vec<TokenStream> = Vec::with_capacity(named_len);
 53→            let mut convert_to_bytes: Vec<TokenStream> = Vec::with_capacity(named_len);
 54→            let mut size: Vec<TokenStream> = Vec::with_capacity(named_len);
 55→            let mut static_sizes: Vec<TokenStream> = Vec::with_capacity(named_len);
 56→            let mut min_size: Vec<TokenStream> = Vec::with_capacity(named_len);
 57→
 58→            for (field, _, with_attr) in fields_insert.iter() {
 59→                let ident = field.ident.as_ref().unwrap();
 60→                let typ = &field.ty;
 61→
 62→                field_names.push(quote! { #ident, });
 63→
 64→                match with_attr {
 65→                    Some(with_attr) => {
 66→                        static_sizes.push(quote! {
 67→                            #with_attr::static_size(core::marker::PhantomData::<#typ>),
 68→                        });
 69→                        min_size.push(quote! {
 70→                            #with_attr::min_size(core::marker::PhantomData::<#typ>),
 71→                        });
 72→                        size.push(
 73→                            quote! { + (match #with_attr::static_size(core::marker::PhantomData::<#typ>) {
 74→                                Some(s) => s,
 75→                                None => #with_attr::size(&self.#ident)
 76→                            }) },
 77→                        );
 78→                        check_bytes.push(quote! {
 79→                            #with_attr::check_bytes(core::marker::PhantomData::<#typ>, slice)?;
 80→                        });
 81→                        from_slice.push(quote! {
 82→                            let #ident: #typ = #with_attr::from_slice(slice)?;
 83→                        });
 84→                        debug_from_slice.push(quote! {
 85→                            let len = slice.len();
 86→                            println!("Field: {}, Type: {}", stringify!(#ident), stringify!(#typ));
 87→                            let res = #with_attr::from_slice(slice).inspect(|v| {
 88→                                println!("len: {len}, {}: {v:?}", stringify!(#ident));
 89→                            }).inspect_err(|err| {
 90→                                println!("len: {len}, err: {err:?}");
 91→                            });
 92→                            let #ident: #typ = res?;
 93→                        });
 94→                        from_slice_unchecked.push(quote! {
 95→                            let #ident: #typ = #with_attr::from_slice_unchecked(slice)?;
 96→                        });
 97→                        from_slice_unsafe.push(quote! {
 98→                            let #ident: #typ = #with_attr::from_slice_unsafe(slice)?;
 99→                        });
100→                        try_convert_to_bytes.push(quote! {
101→                            #with_attr::try_convert_to_bytes(&self.#ident, slice, cursor)?;
102→                        });
103→                        convert_to_bytes.push(quote! {
104→                            #with_attr::convert_to_bytes(&self.#ident, slice, cursor);
105→                        });
106→                    }
107→                    None => {
108→                        from_slice.push(quote! {
109→                            let #ident = <#typ as rapira::Rapira>::from_slice(slice)?;
110→                        });
111→                        debug_from_slice.push(quote! {
112→                            let len = slice.len();
113→                            println!("Field: {}, Type: {}", stringify!(#ident), stringify!(#typ));
114→                            let res = <#typ as rapira::Rapira>::from_slice(slice).inspect(|v| {
115→                                println!("len: {len}, {}: {v:?}", stringify!(#ident));
116→                            }).inspect_err(|err| {
117→                                println!("len: {len}, err: {err:?}");
118→                            });
119→                            let #ident = res?;
120→                        });
121→                        check_bytes.push(quote! {
122→                            <#typ as rapira::Rapira>::check_bytes(slice)?;
123→                        });
124→                        from_slice_unchecked.push(quote! {
125→                            let #ident = <#typ as rapira::Rapira>::from_slice_unchecked(slice)?;
126→                        });
127→                        from_slice_unsafe.push(quote! {
128→                            let #ident = <#typ as rapira::Rapira>::from_slice_unsafe(slice)?;
129→                        });
130→                        try_convert_to_bytes.push(quote! {
131→                            self.#ident.try_convert_to_bytes(slice, cursor)?;
132→                        });
133→                        convert_to_bytes.push(quote! {
134→                            self.#ident.convert_to_bytes(slice, cursor);
135→                        });
136→                        size.push(quote! { + (match <#typ as rapira::Rapira>::STATIC_SIZE {
137→                            Some(s) => s,
138→                            None => self.#ident.size()
139→                        }) });
140→                        static_sizes.push(quote! {
141→                            <#typ as rapira::Rapira>::STATIC_SIZE,
142→                        });
143→                        min_size.push(quote! {
144→                            <#typ as rapira::Rapira>::MIN_SIZE,
145→                        });
146→                    }
147→                }
148→            }
149→
150→            let name_with_generics = build_ident(name, generics);
151→
152→            let debug_parse = if is_debug {
153→                quote! {
154→                    /// Deserializes a value from a byte slice with debug logging.
155→                    /// This method logs the struct name, field names, types, and values during deserialization.
156→                    /// Useful for debugging serialization/deserialization issues.
157→                    #[inline]
158→                    fn debug_from_slice(slice: &mut &[u8]) -> rapira::Result<Self>
159→                    where
160→                        Self: Sized + std::fmt::Debug,
161→                    {
162→                        println!("Struct: {}", stringify!(#name));
