                        });
                        from_slice_unsafe.push(quote! {
                            let #ident = <#typ as rapira::Rapira>::from_slice_unsafe(slice)?;
                        });
                        try_convert_to_bytes.push(quote! {
                            self.#ident.try_convert_to_bytes(slice, cursor)?;
