                        });
                        size.push(quote! { + (match <#typ as rapira::Rapira>::STATIC_SIZE {
                            Some(s) => s,
                            None => self.#ident.size()
                        }) });
                        static_sizes.push(quote! {
                            <#typ as rapira::Rapira>::STATIC_SIZE,
                        });
                        min_size.push(quote! {
                            <#typ as rapira::Rapira>::MIN_SIZE,
                        });
                    }
