            let versioned_method = if struct_version.is_some() {
                quote! {
                    #[inline]
                    fn from_slice_versioned(slice: &mut &[u8], version: u8) -> rapira::Result<Self>
                    where
                        Self: Sized,
                    {
                        #(#from_slice_versioned)*
