}

#[derive(Debug, Rapira, PartialEq)]
enum FullEnum {
    A(String),
    B(u16, u64, #[rapira(with = rapira::zero)] Zero),
    C {
        c1: bool,
        c2: (usize, isize),
        #[rapira(with = rapira::byte_rapira)]
        c3: u8,
