    }

    #[inline]
    pub fn convert_to_bytes<T>(item: &T, slice: &mut [u8], cursor: &mut usize)
    where
        T: Immutable + Pod + Zeroable + Sized,
    {
        let bytes = bytemuck::bytes_of(item);
        extend(slice, cursor, bytes);
    }

    #[inline]
    pub fn try_convert_to_bytes<T>(
        item: &T,
        slice: &mut [u8],
        cursor: &mut usize,
    ) -> crate::Result<()>
    where
        T: Immutable + Pod + Zeroable + Sized,
    {
