    #[inline]
    pub fn convert_from_bytes<T>(slice: &[u8], cursor: &mut usize) -> Option<T>
    where
        T: Immutable + Pod + Zeroable + Sized,
    {
        let bytes = slice.get(*cursor..*cursor + size_of::<T>())?;
